module RefModule(
    Y,
    A1,
    A2,
    A3,
    A4,
    B1
);output Y;
    input A1, A2, A3, A4, B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB;
    supply0 VNB;

    // Use a simple AND gate and invert B1 for active-low disable_sig functionality
    wire disable_sig;

    // Invert B1 for the disable_sig signal
    not u_inv(disable_sig, B1);

    // Output Y is high when disable_sig is active and all A inputs are high
    assign Y = disable_sig & A1 & A2 & A3 & A4;

endmodule
